function initializeDirectories() {
    const audiosDir = filesFolder + 'audios';
    const customDocDir = filesFolder + 'customDoc';
    const transcriptionsDir = filesFolder + 'transcriptions';
    const chunksDir = audiosDir + slash + 'chunks';

    // Verificar si la carpeta 'audios' existe
