    if (!fs.existsSync(customDocDir))
        fs.mkdirSync(customDocDir);
    if (!fs.existsSync(transcriptionsDir))
        fs.mkdirSync(transcriptionsDir);
    if (!fs.existsSync(chunksDir))
        fs.mkdirSync(chunksDir);
    node.warn('folders created ok.');
}

