const moment = require("moment");
const marked = require('marked');
let {
    extraInfo,
    nameOfSources,
    showFragmentsActionBar,
    canDownloadDocuments,
    spSite,
    spFolder,
} = global.get("settings");
const { iconTalkB64, addVideoLink } = global.get("commonUI");

function getVideoUrl(videoName, startTime) {
    if (!videoName.length) return '';
    if (!videoName.startsWith('vd_')) return '';

    let videoNameparsed = videoName
    if (videoName.includes('.')) videoNameparsed = videoName.split('.')[0]

    const baseUrl = `${spSite}${spFolder}${encodeURIComponent(videoNameparsed)}.mp4`;

    const timeParts = startTime.split(':');
