function getSixFirstWords(str) {
    return str.split(/\s+/).slice(0, 6).join(' ');
}

function saveConversation(composeChat, input, response, historyLog = "", context = "", model = "", tokens = "") {
    try {
        let conversationHistory = composeChat.conversation.length > 0 ? composeChat.conversation : [];
        conversationHistory.push({
            timestamp: new Date().toISOString(),
            context: 'General',
            model: model,
            tokens: tokens,
            role: 'user',
            content: input
        });

        conversationHistory.push({
            timestamp: new Date().toISOString(),
            context: context,
            model: model,
            tokens: tokens,
            role: 'assistant',
            content: response
        });
        return conversationHistory
    } catch (error) {
        node.warn('Error saving conversation:' + error);
        throw Error('Error saving conversation:' + error)
    }
}

