// Flatten objects into a single-depth Object
function flattenObject(obj, parentKey = '', separator = '_') {
    let flatObject = {};

    for (let key in obj) {
        if (obj.hasOwnProperty(key)) {
            const newKey = parentKey ? `${parentKey}${separator}${key}` : key;

            if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key])) {
                Object.assign(flatObject, flattenObject(obj[key], newKey, separator));
            } else {
                flatObject[newKey] = obj[key];
            }
        }
    }

    return flatObject;
}


function orderByDocAndRate(dataArray) {
    dataArray.sort((a, b) => {
        if (a.valueUtterance.expected > b.valueUtterance.expected) {
            return -1;
        }
        if (a.valueUtterance.expected < b.valueUtterance.expected) {
            return 1;
        }
        if (a.successRate < b.successRate) {
            return -1;
        }
        if (a.successRate > b.successRate) {
            return 1;
        }
        return 0;
    });
    return dataArray;
}

