const fs = require('fs');
const { filesFolder } = global.get("env")
const { videoTranscriptor, imageInterpreter } = global.get('settings')
const { getFileOnlyName, getFileExtension } = global.get('commonParsers');
const { ALL_VALID_TYPES, VIDEOS_TYPES, IMAGES_TYPES } = global.get('fileExtensionAccepted');

const path = require('path');

function sanitizeFileName(filename) {
    const REGEX_ESPCHARS = /[!@#$%^& *()+{}\[\]:;<>.,?~\\/-]/gm
    const ext = path.extname(filename);
    const baseName = path.basename(filename, ext);
    let sanitized = baseName.replace(REGEX_ESPCHARS, '');
    const accentsMap = {
        'á': 'a', 'é': 'e', 'í': 'i', 'ó': 'o', 'ú': 'u',
        'Á': 'A', 'É': 'E', 'Í': 'I', 'Ó': 'O', 'Ú': 'U',
        'ñ': 'n', 'Ñ': 'N'
    };
    sanitized = sanitized.replace(/[áéíóúÁÉÍÓÚñÑ]/gm, match => accentsMap[match]);

    // const cleanBaseName = baseName.replace(regex, '');
    const cleanBaseName = sanitized;
    return cleanBaseName + ext;
}

if (!msg.payload.data.upload.length) throw Error("The file attached invalid! Max. size allowed its 120Mb.")
const filename = sanitizeFileName(msg.payload.data.upload[0].originalName)
// node.warn(filename)
const extension = getFileExtension(filename)
const nameWithoutExt = getFileOnlyName(filename)
const name = `${getFileOnlyName(filename)}.${extension}`


const file = msg.submission.upload[0].url.split(',');
const dataBinary = file[1];

writeFileLocal(filesFolder, filename, dataBinary)

function writeFileLocal(dir, filename, data) {
    const base64data = data; // tu base64 aquí
    const buffer = Buffer.from(base64data, 'base64');
    const directorioDestino = dir;
    const nombreArchivo = filename;
    const rutaCompleta = `${directorioDestino}/${nombreArchivo}`;
    try {
        fs.writeFileSync(rutaCompleta, buffer);
    } catch (error) {
        node.warn("Hubo un error al subir el fichero al repositorio")
    };
}

msg.topic = {
    filepath: filesFolder + filename,
    keywords: msg.payload.data.keywords,
    name: name,
    nameWithoutExt: nameWithoutExt,
    extension: extension
}

if (!ALL_VALID_TYPES.includes(msg.topic.extension.toLowerCase())
    || (VIDEOS_TYPES.includes(msg.topic.extension.toLowerCase()) && !videoTranscriptor)
    || (IMAGES_TYPES.includes(msg.topic.extension.toLowerCase()) && !imageInterpreter)) return [msg, null]

return [null, msg];

