$(".copy-button").click(function () {
  console.log("copyButton");
  var targetId = $(this).data("target");
  var $targetDiv = $("#" + targetId);
  var $temp = $("<textarea>");
  $("body").append($temp);
  $temp.val($targetDiv.text().trim()).select();
  document.execCommand("copy");
  $temp.remove();
  // alert("Texto copied");
  // Cambiar el icono del botón a un check
  var $buttonIcon = $(this).find("i");
  $buttonIcon.removeClass("fa-copy").addClass("fa-check");

  // Restaurar el icono de copiar después de 2 segundos
  setTimeout(() => {
    $buttonIcon.removeClass("fa-check").addClass("fa-copy");
  }, 1000);
});

