const xlsx = require('xlsx');
const { filesFolder } = global.get("env")

const conversation = msg.payload.data.conversation
const excelData = [];

let timestamp;
let question;
for (let i = 0; i < conversation.length; i++) {
    const item = conversation[i];

    if (item.role === 'user') {
        timestamp = item.timestamp;
        question = item.content;
    }

    if (item.role === 'assistant') {
        let answer = item.content;
        let document = item.context;

        const responseItem = {
            Date: timestamp,
            Document: document,
            Question: question,
            Answer: answer

        }
        excelData.push(responseItem);
        timestamp = '';
        question = '';
        answer = '';
        document = '';
    }
}
// node.warn(excelData)
// Crea un libro de Excel
const wb = xlsx.utils.book_new();
const ws = xlsx.utils.json_to_sheet(excelData);
xlsx.utils.book_append_sheet(wb, ws, 'export');

const fileExport = filesFolder + 'chat-export.xlsx'
// Escribe el libro de Excel a un archivo
xlsx.writeFile(wb, fileExport);

node.warn('Excel Created OK.');

msg.downloadFileSubmission = {
    "data": Buffer.from(fileExport),
    "fileName": 'chat-export.xlsx'
}

return msg;

