function getColor() {
    // Generar valores aleatorios para R, G y B
    const r = 128;
    const g = 64;
    const b = 255;

    // Formatear los valores para que siempre tengan 2 dígitos
    const formattedR = String(r).padStart(2, '0');
    const formattedG = String(g).padStart(2, '0');
    const formattedB = String(b).padStart(2, '0');

    // Devolver el color en formato "rgb(00, 00, 255)"
    return `rgb(${formattedR}, ${formattedG}, ${formattedB}`;
}


function countConfidenceValues(dispersionQuestionsChart) {
    const categories = ['low', 'average', 'high'];
    const result = {};

    // Function to count values for each confidence level
    const countValues = (arr, category) => {
        arr.forEach(item => {
            const { confidence, value } = item;
            if (!result[value]) {
                result[value] = { document: value, low: 0, average: 0, high: 0 };
            }
            result[value][category]++;
        });
    };

    categories.forEach(category => {
        countValues(dispersionQuestionsChart[category], category);
    });

    return Object.values(result);
}

