const { v4: uuidv4 } = require('uuid');
const sessionCode = msg.composeChat && msg.composeChat.id ? msg.composeChat.id : uuidv4();
try {
    // Initialize with undefined 
    let startTime = null;
    let endTime = null;

    const timeRegex = /\d{1,2}:\d{2}/g;

    if (msg.sourceChunks[0]){
        const chunk = msg.sourceChunks[0];  
        const times = chunk.content.match(timeRegex);

        if (times) {
            const firstTime = timeToMinutes(times[0]);
            const lastTime = timeToMinutes(times[times.length - 1]);

            if (!startTime || firstTime < timeToMinutes(startTime)) {
                startTime = times[0];
            }
            if (!endTime || lastTime > timeToMinutes(endTime)) {
                endTime = times[times.length - 1];
            }
        }

    }

    msg.evaResponse = {
        sessionCode: sessionCode,
        nlpResponse: { name: msg.sourceChunks[0] ? msg.sourceChunks[0].sourcefile : 'Document' },
        sourcefile: msg.sourceChunks.map(el => el.sourcefile) || [],
        answers: [{
            content: msg.payload.text,
            startTime: startTime,
            endTime: endTime
        }]
    }
    msg.auditnumberOfCalls++;
    msg.audittokensCount += msg.payload.totalTokens;

} catch (error) {
    node.warn(error)
    throw Error(error)
};

function timeToMinutes(time) {
    const [hours, minutes] = time.split(':').map(Number);
    return hours * 60 + minutes;
}

return msg;

