const xlsx = require('xlsx');
const fs = require('fs');
const { filesFolder } = global.get('env')

msg.topicSheet = []
if (msg.topic.extension != 'xlsx' && msg.topic.extension != 'xlsm')
    return msg

const formatRow = (row, headers) => {
    return headers
        .map((header, index) => {
            const value = row[index];
            return value ? `${header}: ${value}` : null;
        })
        .filter(Boolean)
        .join('. ') + '.\n';
};

// Función para convertir cada hoja en un archivo txt
const convertSheetToTxt = (sheet, sheetName, originalName) => {
    const range = xlsx.utils.decode_range(sheet['!ref']);
    const headers = [];
    const rows = [];

    // Leer encabezados
    for (let C = range.s.c; C <= range.e.c; ++C) {
        const cellAddress = xlsx.utils.encode_cell({ c: C, r: range.s.r });
        const cell = sheet[cellAddress];
        headers.push(cell ? cell.v : `Column${C}`);
    }

    // Leer filas
    for (let R = range.s.r + 1; R <= range.e.r; ++R) {
        const row = [];
        for (let C = range.s.c; C <= range.e.c; ++C) {
            const cellAddress = xlsx.utils.encode_cell({ c: C, r: R });
            const cell = sheet[cellAddress];
            row.push(cell ? cell.v : '');
        }
        rows.push(formatRow(row, headers));
    }

    // Escribir en archivo txt
    const newFilename = `${originalName.split('.')[0]}_${sheetName}.txt`
    const filePath = filesFolder + newFilename;
    fs.writeFileSync(filePath, rows.join('\n'), 'utf8');

    let keywords;
    if (msg.payload.data && Array.isArray(msg.payload.data.keywords) && msg.payload.data.keywords.length > 0) {
        keywords = [...msg.payload.data.keywords]
    } else {
        keywords = []
    }

    msg.topicSheet.push({
        filepath: filePath,
        keywords: keywords,
        name: newFilename,
        extension: 'txt'
    })
};

// Función principal para convertir todo el archivo Excel
const convertExcelToTxt = (filePath, filename) => {
    const workbook = xlsx.readFile(filePath);
    workbook.SheetNames.forEach(sheetName => {
        const sheet = workbook.Sheets[sheetName];
        try {
            convertSheetToTxt(sheet, sheetName, filename);
        } catch (error) {
            node.warn(error + " / " + msg.topic.name)
        };
    });
};

const excelFilePath = msg.topic.filepath;
convertExcelToTxt(excelFilePath, msg.topic.name);

return msg;

