const axios = require('axios');
const { filesFolder } = global.get('env');
const path = require('path');
const ffmpeg = require('fluent-ffmpeg');
const ffmpegPath = require('ffmpeg-static');
const ffprobePath = require('ffprobe-static').path;
const FormData = require('form-data');
const { spUser, spPass, spFolder, spSite, videoTranscriptor } = global.get('settings')
const { getSessionEnabler, whisperEndpoint } = global.get('commonAPI')
const transcriptionsDir = path.join(filesFolder, 'transcriptions');
const userOktaId = msg.__axetFlowsSecurityContext.oktaId

ffmpeg.setFfmpegPath(ffmpegPath);
ffmpeg.setFfprobePath(ffprobePath);

if ((msg.topic.extension != 'mp4' &&
    msg.topic.extension != 'avi' &&
    msg.topic.extension != 'mov' &&
    msg.topic.extension != '') || !videoTranscriptor)
    return msg


const splitAudioIntoChunks = (inputPath, outputDir, name) => {
    return new Promise((resolve, reject) => {
        ffmpeg(inputPath)
            .output(path.join(outputDir, '%03d.mp3')) // Especificar el nombre del archivo de salida
            .outputOptions([
                '-f', 'segment',
                '-segment_time', '1200', // 20 minutos = 1200 segundos
                '-reset_timestamps', '1',
            ])
            .on('end', function () {
                resolve();
            })
            .on('error', function (err) {

                reject(new Error('Error durante la segmentación: ' + err.message));
            })
            .run();
    });
};


let apiKey = ''
try {
    apiKey = await getSessionEnabler(userOktaId)

} catch (error) {
    node.warn(error)
    throw Error(error)
};

async function generateTranscription(videos) {
    for (let video of videos) {
        const inputVideoPath = path.join(filesFolder, video.fileName);
        const outputAudioPath = path.join(filesFolder, 'audios', `${video.name}.mp3`);
        const audioChunksDir = path.join(filesFolder, 'audios', 'chunks', video.name);


        // Convert video to audio
        await convertVideoToAudio(inputVideoPath, outputAudioPath);
        const duration = await getAudioDuration(outputAudioPath);

        let totalDuration = 0;
        let fullTranscription = '';

        if (duration > 1200) { // More than 20 minutes
            if (!fs.existsSync(audioChunksDir)) {
                fs.mkdirSync(audioChunksDir);
                node.warn('Directory created');
            } else {
                node.warn('Directory already exists');
            }
            fs.readdirSync(audioChunksDir).forEach(file => fs.unlinkSync(path.join(audioChunksDir, file)));
            await splitAudioIntoChunks(outputAudioPath, audioChunksDir, video.name);
            const audioChunks = fs.readdirSync(audioChunksDir);

            for (let chunk of audioChunks) {
                const chunkPath = path.join(audioChunksDir, chunk);
                const transcription = await transcribeAudio(chunkPath, apiKey, totalDuration);
                totalDuration += await getAudioDuration(chunkPath);  // Add chunk duration to the total
                fullTranscription += transcription + '\n';
            }

        } else {
            node.warn(`Call to transcribeAudio`)
            fullTranscription = await transcribeAudio(outputAudioPath, apiKey, 0);
        }

        node.warn(`End-transcribeAudio`)
        fs.writeFileSync(path.join(transcriptionsDir, `${video.name}.txt`), fullTranscription);
    }
}


function convertVideoToAudio(inputPath, outputPath) {
    return new Promise((resolve, reject) => {
        ffmpeg(inputPath)
            .toFormat('mp3')
            .on('end', resolve)
            .on('error', err => reject(new Error('Error during conversion: ' + err.message)))
            .save(outputPath);
    });
}

function getAudioDuration(inputPath) {
    return new Promise((resolve, reject) => {
        ffmpeg.ffprobe(inputPath, (err, metadata) => {
            if (err) reject(new Error('Error getting audio duration: ' + err.message));
            resolve(metadata.format.duration);
        });
    });
}

async function transcribeAudio(filePath, apiKey, offset) {
    const formData = new FormData();
    formData.append('file', fs.createReadStream(filePath));
    formData.append('model', 'whisper-1');
    formData.append('response_format', 'verbose_json');
    formData.append('timestamp_granularities', 'segment');

    const response = await axios.post(whisperEndpoint, formData, {
        headers: {
            'Authorization': `Bearer ${apiKey}`,
            ...formData.getHeaders()
        }
    });
    // node.warn(response.data)

    // Adjust timestamps using the offset
    const transcriptionWithAdjustedTimestamps = response.data.segments.map(segment => {
        const adjustedStart = segment.start + offset;
        const adjustedEnd = segment.end + offset;
        const startTime = convertSecondsToMinutes(adjustedStart);
        const endTime = convertSecondsToMinutes(adjustedEnd);
        return `[${startTime} - ${endTime}] ${segment.text}`;
    }).join('\n');

    return transcriptionWithAdjustedTimestamps;
}


function convertSecondsToMinutes(seconds) {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = Math.floor(seconds % 60);
    return `${minutes}:${remainingSeconds < 10 ? '0' : ''}${remainingSeconds}`;
}


async function saveToSP(name, filepath) {

    const fs = require("fs");
    const spsave = require("spsave").spsave;

    const coreOptions = {
        siteUrl: spSite
    };
    const creds = {
