    };

    const fileOptions = {
        folder: spFolder,
        fileName: name,
        // fileContent: fs.createReadStream(filepath)
        fileContent: fs.readFileSync(filepath)
    };

    try {
        await spsave(coreOptions, creds, fileOptions)
        node.warn('saved Sharepoint Video');
        return msg;

    } catch (error) {
