// Draw the Conversation for the UI box
function conversationPretty(jsonChat = [], question = "") {
    try {
        const sourceFiles = msg.streambatch.map((el) => el);
        const evaOptions = msg.streamOptions.map((el) => el);

        function drawEvaOptions(options = []) {
            let uniqueOptions = [...new Set(options.filter((el) => el))].filter(item => item !== null && item !== undefined);

            let optionshtml = uniqueOptions
                .map((el) => {
                    return `<div class="action-buttons"><button class="no-border selectEvaOption badge badge-light" aria-controls="${el.value}" id="${el.value}" ref="button"> ${el.value} </button> </div>`;
                })
                .join("");

            return optionshtml;
        }

        function drawActionFiles(sourceFiles = []) {
            let uniqueFiles = [...new Set(sourceFiles)].filter(item => item !== null && item !== undefined);
            if (uniqueFiles.length == 0) return ``;

            return `<div class="dropdown inline">
                        <button class="dropdown-toggle" type="button" id="drawActionFiles" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false">
                            <span class="fa fa-list"> </span> 
                        </button>
                        <div class="dropdown-menu" aria-labelledby="drawActionFiles" x-placement="top-start" style="position: absolute; will-change: transform; top: 0px; left: 0px; transform: translate3d(0px, -116px, 0px);">
                            ${uniqueFiles
                    .map(
                        (file) =>
                            `<span id="${file}" class="dropdown-item summarizeFile"> ${file.length && file.includes('vd_') ? '<span class="badge badge-secondary">Video</span>' : '<span class="badge badge-primary">Document</span>'}  ${file.split('.') ? file.split('.')[0] : file }</span>`
                    )
                    .join("")}
                        </div>
                    </div>
                    `;
        }

        const commonActionBar = (idx) => `
            <button class="copy-button" data-target="text-to-copy-${idx}"><i class="fa fa-copy action-bar-button" aria-hidden="true"></i></button>
        `;
        function drawActionChunks(sourceChunks = []) {
            let uniqueChunks = [...new Set(sourceChunks)].filter(item => item !== null && item !== undefined);
            if (uniqueChunks.length == 0) return ``;
            // node.warn(uniqueChunks)
            const content = uniqueChunks
                .map((chunk) => {
                    return `<div>
                            <p class="chunk-preview">
                                ${chunk.content}
                            </p>
                            <p>Source <span id="${chunk.storageName
                        }" data-dismiss="modal" class="badge badge-primary ${canDownloadDocuments ? "selectDownloadDocument" : ""
                        }">${canDownloadDocuments ? '<i class="fa fa-download"></i>' : ""} ${chunk.sourcefile
                        } </span> - Score: ${parseInt(chunk.score * 100)} %</p>
                        </div>`;
                })
                .join("<hr>");
            return `
            <button class="chunks-button dropdown-toggle" type="button" data-toggle="modal" data-target="#chunksModal"><i class="fas fa-link"></i></button>
            <!-- Modal Chunks -->
              <div class="modal fade" id="chunksModal" tabindex="-1" role="dialog" aria-labelledby="exampleModalLabel" aria-hidden="true">
                  <div class="modal-dialog modal-lg" role="document">
                      <div class="modal-content">
                          <div class="modal-header">
                              <h5 class="modal-title" id="exampleModalLabel">Knowledge References</h5>
                              <button type="button" class="close" data-dismiss="modal" aria-label="Close">
                                  <span aria-hidden="true">&times;</span>
                              </button>
                          </div>
                          <div class="modal-body">
                            ${content}
                          </div>
                          <div class="modal-footer">
                              <button type="button" class="btn btn-secondary btn-fix btn-light" data-dismiss="modal">Close</button>
                          </div>
                      </div>
                  </div>
              </div>      
            <!-- Modal Chunks END  -->
              `;
        }

        const actionBar = (lastItemBool, idx) => {
            return `
            <div class="action-bar">
                ${commonActionBar(idx)}
                ${lastItemBool == idx && nameOfSources
                    ? drawActionFiles(sourceFiles)
                    : ""
                }
                ${lastItemBool == idx && showFragmentsActionBar
                    ? drawActionChunks(msg.sourceChunks)
                    : ""
                }
            </div>
        `;
        };

        const lastItemBool = jsonChat.length - 1;
        let txtChat = "";

        jsonChat.forEach(function (sentence, idx) {

            let sentenceRewrite = marked.parse(sentence.content);
            sentenceRewrite = rewriteResponse(sentenceRewrite);

            if (sentence.role == "user") {
                txtChat += `<li class="clearfix">
                      <div class="message-data text-right">
                        <span class="message-data-time">${moment(
                    sentence.timestamp
                ).format("YYYY/MM/DD HH:mm")}</span>
                        <span class="badge badge-primary">${sentence.context
                    }</span>
                        <span class="fa fa-user"></span> 
                      </div>
                      <div class="message other-message float-right">
                        ${sentence.content}
                      </div>
                    </li>
                  `;
            } else {
                const startTime = msg.evaResponse.answers[0].startTime || "0:00"; // Default to 0:00 if no time is available
                const videoLink = addVideoLink(getVideoUrl(sentence.context, startTime));
                let extraContent = "";
                if (extraInfo) {
                    extraContent += sentence.model
                        ? `<span class="badge badge-primary">${sentence.model ? sentence.model.toUpperCase() : ""
                        } ${sentence.tokens
                            ? " | Tokens: " + sentence.tokens
                            : " | Tokens: -"
                        } 
                        </span>`
                        : "";
                }
                txtChat += `<li class="clearfix">
                      <div class="message-data">
                        <img src="${iconTalkB64}" alt="axets">
                        <span class="message-data-time">${moment(
                    sentence.timestamp
                ).format("YYYY/MM/DD HH:mm")}</span>
                        ${extraContent ? extraContent : ""} 

                      </div>
                      <div class="message my-message"><div id="text-to-copy-${idx}">${sentenceRewrite}</div>${videoLink} ${drawEvaOptions(
                    evaOptions
                )} ${actionBar(lastItemBool, idx)}</div> 
                    </li>
                  `;
            }
        });

        return txtChat;
    } catch (error) {
        node.warn(error);
        return "An issue happened loading chat...";
    }
}

// Force AI response if blanks
function rewriteResponse(sentence = "") {
    const NORESPONSE = `It was not possible to process the question, I encourage you to rephrase your question or ask a different one to get an appropriate answer.`;
    let sentenceRewrite = sentence || NORESPONSE;
    return sentenceRewrite;
}

return msg;

