function saveConversation(composeChat, input, response, historyLog = "", context = "", model = "", tokens = "") {
    try {
        let conversationHistory = composeChat.conversation.length > 0 ? composeChat.conversation : [];
        conversationHistory.push({
            timestamp: new Date().toISOString(),
            context: msg.topic.name || 'General',
            model: model,
            tokens: tokens,
            role: 'user',
            content: input
        });

        conversationHistory.push({
            timestamp: new Date().toISOString(),
            context: context,
            model: model,
            tokens: tokens,
            role: 'assistant',
            content: response
        });
        return conversationHistory
