if (msg.submission.historyLog) {
  name = msg.submission.name
  user = msg.submission.user
  historyLog = msg.submission.historyLog
  conversation = msg.submission.conversation
}

// try to read chat
try {
  msg.submission.chatbox = conversationPretty(conversation)

  if (msg.submission.chatbox.length == 0) {

    // Initial Message
    msg.streamOptions = initialCustomQuestions.map(el => { return { value: el } })
    let addOptionsMSG = msg.streamOptions.length ? `<br> I suggest you start with one of the following example questions: <br>` : '';

    msg.submission.chatbox = conversationPretty([{
      "timestamp": moment(),
      "context": "Welcome",
      "model": "",
      "tokens": "",
      "role": "IA",
      "content": `Hi, I'm Axet Talk, Attatch your document and fill in the field and ask any questions in your favorite language, I will be happy to address your inquiries... ${addOptionsMSG}`
    }])
  }

} catch (error) {
  node.warn(error)
  node.warn("Nueva conversacion...")
  msg.submission.chatbox = "Attatch your document and fill in the field and ask any questions, we will be happy to address your inquiries..."
};


// Extra functions
// Extra functions
// Extra functions

// Draw the Conversation for the box
function conversationPretty(jsonChat = [], question = "") {
  try {
    const evaOptions = msg.streamOptions ? msg.streamOptions.map(el => el) : [];
    function drawEvaOptions(options = []) {
      let uniqueOptions = [...new Set(options.filter(el => el))];

      let optionshtml = uniqueOptions.map(el => {
        return `<button class="no-border selectEvaOption badge badge-light" aria-controls="${el.value}" id="${el.value}" ref="button"> ${el.value} </button> `
      }).join('')

      return optionshtml
    }

    const commonActionBar = (idx) => `
            <button class="copy-button" data-target="text-to-copy-${idx}"><i class="fa fa-copy action-bar-button" aria-hidden="true"></i></button>
        `

    function drawActionChunks(sourceChunks = []) {
      let uniqueChunks = [...new Set(sourceChunks)]
      if (uniqueChunks.length == 0)
        return ``
      const content = uniqueChunks.map(chunk => {
        return `<div>
          <p class="chunk-preview">
            ${chunk.content}
          </p>
          <p>Source: ${chunk.sourcefile} - Score: ${parseInt(chunk.score * 100)} %</p>
        </div>`
      }).join('<hr>')
      return `<!-- Modal Chunks -->
              <div class="modal fade" id="chunksModal" tabindex="-1" role="dialog" aria-labelledby="exampleModalLabel" aria-hidden="true">
                  <div class="modal-dialog modal-lg" role="document">
                      <div class="modal-content">
                          <div class="modal-header">
                              <h5 class="modal-title" id="exampleModalLabel">Knowledge References</h5>
                              <button type="button" class="close" data-dismiss="modal" aria-label="Close">
                                  <span aria-hidden="true">&times;</span>
                              </button>
                          </div>
                          <div class="modal-body">
                            ${content}
                          </div>
                          <div class="modal-footer">
                              <button type="button" class="btn btn-secondary btn-fix btn-light" data-dismiss="modal">Close</button>
                          </div>
                      </div>
                  </div>
              </div>      
              `
    }


    const actionBar = (lastItemBool, idx) => {
      return `
            <div class="action-bar">
                ${commonActionBar(idx)}
            </div>
        `}

    const lastItemBool = jsonChat.length - 1;
    let txtChat = "";

    jsonChat.forEach(function (sentence, idx) {

      let sentenceRewrite = marked.parse(sentence.content)
      sentenceRewrite = rewriteResponse(sentenceRewrite)

      if (sentence.role == "user") {
        txtChat += `<li class="clearfix">
                      <div class="message-data text-right">
                        <span class="message-data-time">${moment(sentence.timestamp).format("YYYY/MM/DD HH:mm")}</span>
                        <span class="badge badge-primary">${sentence.context}</span>
                        <span class="fa fa-user"></span> 
                      </div>
                      <div class="message other-message float-right">
                        ${sentence.content}
                      </div>
                    </li>
                  `
      } else {
        let extraContent = ""
        if (extraInfo) {
          extraContent += sentence.model ?
            `<span class="badge badge-primary">${sentence.model ? sentence.model : ""} ${sentence.tokens ? " | Tokens: " + sentence.tokens : " | Tokens: -"} 
                        </span>` : ""
        }
        txtChat += `<li class="clearfix">
                      <div class="message-data">
                        <img src="${iconTalkB64}" alt="axets">
                        <span class="message-data-time">${moment(sentence.timestamp).format("YYYY/MM/DD HH:mm")}</span>
                        ${extraContent ? extraContent : ""} 

                      </div>
                      <div class="message my-message"><div id="text-to-copy-${idx}">${sentenceRewrite}</div>
                      ${drawEvaOptions(evaOptions)} ${showActionBar ? actionBar(lastItemBool, idx) : ""}
                      </div> 
                    </li>
                  `
      }
    });

    return txtChat;
  } catch (error) {
    node.warn(error);
    return "An issue happened loading chat...";
  }
}

// Force AI response if blanks
function rewriteResponse(sentence = "") {
  const NORESPONSE = `It was not possible to process the question, I encourage you to rephrase your question or ask a different one to get an appropriate answer.`
  let sentenceRewrite = sentence || NORESPONSE;
  return sentenceRewrite
}


return msg;

