const PDFParse = require('pdf-parse');
const WordExtractor = require('word-extractor');
const fs = require('fs');
const fsPromise = require('fs').promises;
const officeParser = require('officeparser');
const path = require('path');
const xlsx = require('xlsx');
const qp = require('quoted-printable');
const { fromString: convert } = require('html-to-text');

//const REGEXCLEANPROMPT_403 = /\.(exe|bat|cmd|com|msi|sh|bin|jar|js|vbs|ps1|py|php|pl|docm|dotm|xlsm|xltm|pptm|zip|rar|7z|gz|tar\.gz|iso|img|dmg|sys|dll|drv|ini|scr|cpl|pif|xhtml)\b|(?<!\.)\bprompt\b/gm
const REGEXCLEANPROMPT_403 = /<|>|\.(exe|bat|cmd|com|msi|sh|bin|jar|js|vbs|ps1|py|php|pl|docm|dotm|xlsm|xltm|pptm|zip|rar|7z|gz|tar\.gz|iso|img|dmg|sys|dll|drv|ini|scr|cpl|pif|xhtml)\b|(?<!\.)\bprompt\b/gm;

function getFileNameWithExt(filename) {
    return path.basename(filename);
}

function getFileExtension(filename) {
    return path.extname(filename).slice(1).toLowerCase();
}

function getFileOnlyName(filename) {
    const extension = path.extname(filename).toLowerCase();
    return path.basename(filename, extension);
}


function streamSelectContext(stream, threshold = 1) {
    let contentOutput = '';
    stream.slice(0, threshold).forEach((doc) => {
        contentOutput += `---\n${doc.content}\n`;
    });
    return contentOutput;
}

function countTokens(text) {
    let totalTokens = 0
    try {
        const words = text.split(/\s+/);
        const punctuation = text.split(/[\s\w]+/).filter(Boolean);
        const wordCount = words.length;
        const punctuationCount = punctuation.length;
        totalTokens = wordCount + punctuationCount;

    } catch (error) {
        totalTokens = 1
    };
    return totalTokens;
}

async function getTextFromPdf(pdfPath, limit = 4000) {
    const dataBuffer = fs.readFileSync(pdfPath);
    const text = await PDFParse(dataBuffer);
    const textArray = text.text.split(/(?<=\n)/);
    const textArraySplitted = [];
    let textSplitted = '';

    textArray.forEach((element) => {
        if (textSplitted.length + element.length < limit) {
            textSplitted += element;
        } else {
            textArraySplitted.push(textSplitted);
            textSplitted = element;
        }
    });

    textArraySplitted.push(textSplitted);
    return textArraySplitted;
}

function enhanceTextFormat(textRaw) {
    let output = ''
    output = detectAndFormatTables(textRaw);
    return output;
}

async function convertoPdfToText(data) {
    const pdfText = await PDFParse(data);
    return pdfText.text;
}

function convertBase64ToBuffer(data) {
    const dataBinary = Buffer.from(data.split(',')[1], 'base64');
    fs.writeFileSync('/internal-storage-files/files/save.txt', dataBinary);
    return dataBinary;
}

function convertTextToBuffer(data) {
    const dataBinary = Buffer.from(data);
    return dataBinary;
}

async function convertDocToText(data) {
    const extractor = new WordExtractor();
    const extracted = await extractor.extract(data);
    return extracted.getBody();
}

async function convertDocToMdText(inputFile) {
    try {
        const data = await fsPromise.readFile(inputFile, { encoding: 'latin1' });
        const decodedData = qp.decode(data);
        const utf8Data = Buffer.from(decodedData, 'latin1').toString('utf8');
        let plainText = convert(utf8Data, {
            wordwrap: 130
        });

        //Caso si el .doc es "Pagina web de un solo archivo tambien *.mht, *.mhtml"
        if (plainText.includes("admite archivos de almacenamiento web")) {
            throw Error('Invalid type of document.')
        }
        return plainText;
    } catch (err) {
        node.warn(err);
        throw Error('Invalid type of document.')

    }
}


function escapeRegExp(content) {
    return content.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');  // Escapes special characters for regex
}

function detectAndFormatTables(text = '') {
    const lines = text.split(/\r?\n/);
    let inTable = false;
    let tableMarkdown = '';
    let currentTable = [];
    lines.forEach(line => {
        if (line.trim() && line.includes('\t')) {
            currentTable.push(line.split('\t').map(cell => cell.trim()));
            inTable = true;
        } else {
            if (inTable && currentTable.length) {
                // Process the accumulated table rows into Markdown table format
                tableMarkdown += formatTableToMarkdown(currentTable) + '\n';
                currentTable = [];
            }
            inTable = false;
            tableMarkdown += line + '\n';
        }
    });

    // Catch any table at the end of the document
    if (inTable && currentTable.length) {
        tableMarkdown += formatTableToMarkdown(currentTable) + '\n';
    }

    return tableMarkdown;
}

function formatTableToMarkdown(table) {
    if (table.length === 0) return '';
    // Determine the maximum width of each column
    const columnCount = Math.max(...table.map(row => row.length)); // Encuentra el número máximo de columnas
    const maxWidths = Array.from({ length: columnCount }, (_, i) => (
        Math.max(...table.map(row => (row[i] || '').length))
    ));

    // Create the header row
    const headerRow = table[0].map((cell, i) => (cell || '').padEnd(maxWidths[i])).join(' | ');
    const dividerRow = maxWidths.map(width => '-'.repeat(width)).join(' | ');

    // Create the body rows
    const bodyRows = table.slice(1).map(row =>
        row.map((cell, i) => (cell || '').padEnd(maxWidths[i])).join(' | ')
    );

    return `| ${headerRow} |\n| ${dividerRow} |\n| ${bodyRows.join(' |\n| ')} |`;
}

async function convertPPTXorOfficeFileToTxt(inputFile) {
    // A Node.js library to parse text out of any office file. 
    // Currently supports docx, pptx, xlsx and odt, odp, ods..
    const config = {
        newlineDelimiter: " ",
        ignoreNotes: true
    }

    try {
        const data = await officeParser.parseOfficeAsync(inputFile);
        return data;
    } catch (err) {
        node.warn(err);
        throw Error('Error processing file!')
    }
}

function trimLines(data) {
    const lines = data.split('\n').filter(line => line != ' ');
    // node.warn(lines.slice(0, 50))
    const cleanedLines = lines.map(line => line.trim());
    const cleanedText = cleanedLines.join('\n');
    return cleanedText
}



const formatRow = (row, headers) => {
    return headers
        .map((header, index) => {
            const value = row[index];
            return value ? `${header}: ${value}` : null;
        })
        .filter(Boolean)
        .join('. ') + '.\n';
};

// Función para convertir cada hoja en un archivo txt
const convertSheetToTxt = (sheet) => {
    const range = xlsx.utils.decode_range(sheet['!ref']);
    const headers = [];
    const rows = [];

    // Leer encabezados
    for (let C = range.s.c; C <= range.e.c; ++C) {
        const cellAddress = xlsx.utils.encode_cell({ c: C, r: range.s.r });
        const cell = sheet[cellAddress];
        headers.push(cell ? cell.v : `Column${C}`);
    }

    // Leer filas
    for (let R = range.s.r + 1; R <= range.e.r; ++R) {
        const row = [];
        for (let C = range.s.c; C <= range.e.c; ++C) {
            const cellAddress = xlsx.utils.encode_cell({ c: C, r: R });
            const cell = sheet[cellAddress];
            row.push(cell ? cell.v : '');
        }
        rows.push(formatRow(row, headers));
    }
    return rows.join('\n')
};

// Función principal para convertir todo el archivo Excel
const convertExcelToTxt = (filePath) => {
    const workbook = xlsx.readFile(filePath);
    // solo toma el 1ero
    workbook.SheetNames.slice(0, 1).forEach(sheetName => {
        const sheet = workbook.Sheets[sheetName];
        try {
            const sheetDataTxt = convertSheetToTxt(sheet);
            return sheetDataTxt
        } catch (error) {
            node.warn(error)
        };
    });
};

const commonParsers = {
    getFileNameWithExt,
    getFileExtension,
    getFileOnlyName,
    convertDocToText,
    convertDocToMdText,
    convertTextToBuffer,
    convertBase64ToBuffer,
    enhanceTextFormat,
    countTokens,
    streamSelectContext,
    getTextFromPdf,
    convertoPdfToText,
    convertPPTXorOfficeFileToTxt,
    trimLines,
    convertExcelToTxt,
    convertSheetToTxt,
    formatRow,
    REGEXCLEANPROMPT_403
}

// node.warn(commonParsers)
global.set('commonParsers', commonParsers)

return msg

