const fs = require('fs');
const path = require("path");
const { filesFolder } = global.get('env');
const { enhanceTextFormat, trimLines, convertPPTXorOfficeFileToTxt } = global.get('commonParsers');

if (msg.topic.extension != 'pptx')
    return msg;

const inputPath = msg.topic.filepath;
const parseName = path.parse(msg.topic.name);
const outputPath = `${filesFolder}${parseName.name}.txt`;
const outputName = `${parseName.name}.txt`;

let dataFileTxt = ''
let tempContent = ''
tempContent = await convertPPTXorOfficeFileToTxt(inputPath)
dataFileTxt = enhanceTextFormat(tempContent)
dataFileTxt = trimLines(dataFileTxt)

fs.writeFileSync(outputPath, dataFileTxt)
node.warn('Conversion completed successfully.');

msg.topic.filepath = outputPath
msg.topic.name = outputName
msg.topic.extension = 'txt'

return msg;

