const fs = require('fs');
const axios = require('axios');
const path = require('path');
const imagesDir = '/internal-storage-files/files/images/';
const { getSessionEnabler, gpt4ominiEndpoint } = global.get('commonAPI');
const { filesFolder } = global.get('env');
const userOktaId = msg.__axetFlowsSecurityContext ? msg.__axetFlowsSecurityContext.oktaId : '00u9pwnma4UGDV0dy417';
const parseName = path.parse(msg.topic.name);
const outputPath = `${filesFolder}${parseName.name}.txt`;
const outputName = `${parseName.name}.txt`;
const images = filesFolder + 'images';

if (!fs.existsSync(images))
    fs.mkdirSync(images);

function convertImagesToBase64(dirPath) {
    const base64Images = [];
    const files = fs.readdirSync(dirPath);

    files.forEach((file) => {
        const filePath = path.join(dirPath, file);
        if (path.extname(file).toLowerCase() === '.png') {
            const fileData = fs.readFileSync(filePath);
            const base64 = fileData.toString('base64');

            base64Images.push({
                filename: file,
                base64: `data:image/png;base64,${base64}`
            });
        }
    });
    return base64Images;
}

const base64Images = convertImagesToBase64(imagesDir);
//msg.base64Images = base64Images;
fs.writeFileSync(outputPath, '', 'utf8');
msg.allUsage=[];

for (const image of base64Images) { //max images permited???
    let apiKey = '';
    try {
        node.warn('------------userOktaId-----------');
        node.warn(userOktaId);
        apiKey = await getSessionEnabler(userOktaId);
    } catch (error) {
        node.warn("Error getting API key: " + error.message);
        throw error;
    }

    try {
        // Step 1: Perform OCR on the image
        //node.warn("Performing OCR on image...");
        // Step 5: Prepare data for the API request
        const data = {
            "model": "gpt-4o-mini",
            "temperature": 0.2,
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "text",
                            "text": `You will be provided with an image of a pdf page or a slide. Your goal is to talk about the content that you see, in technical terms, as if you were delivering a presentation.

                                    If there are diagrams, describe the diagrams and explain their meaning.
                                    For example: if there is a diagram describing a process flow, say something like "the process flow starts with X then we have Y and Z..."

                                    If there are tables, describe logically the content in the tables
                                    For example: if there is a table listing items and prices, say something like "the prices are the following: A for X, B for Y..."

                                    DO NOT include terms referring to the content format
                                    DO NOT mention the content type - DO focus on the content itself
                                    For example: if there is a diagram/chart and text on the image, talk about both without mentioning that one is a chart and the other is text.
                                    Simply describe what you see in the diagram and what you understand from the text.

                                    You should keep it concise, but keep in mind your audience cannot see the image so be exhaustive in describing the content.

                                    Exclude elements that are not relevant to the content:
                                    DO NOT mention page numbers or the position of the elements on the image.

                                    ------

                                    If there is an identifiable title, identify the title to give the output in the following format:

                                    {TITLE}

                                    {Content description}

                                    If there is no clear title, simply return the content description.`
                        },
                        {
                            "type": "image_url",
                            "image_url": {
                                "url": image.base64,
                                "detail": "high"
                            }
                        }
                    ]
                }
            ],
        };

        let config = {
            method: 'post',
            maxBodyLength: Infinity,
            url: gpt4ominiEndpoint,
            headers: {
                'Authorization': 'Bearer ' + apiKey,
            },
            data: data
        };

        // Step 6: Send the API request
        node.warn("Sending request to API...");
        const res = await axios.request(config);

        if (res && res.data && res.data.usage) {
            msg.allUsage.push(res.data.usage);
        }

        // Step 7: Save the response content as .txt file
        //fs.appendFileSync(outputPath, `RESPUESTA para ${image.filename}` + '\n', 'utf8'); //pre
        fs.appendFileSync(outputPath, res.data.choices[0].message.content + '\n', 'utf8');

    } catch (error) {
        node.warn("Error during SLIDE IMAGE API request: " + error.message);
        throw Error('Error during indexing the SLIDE IMAGE! ' + error.message)
    }
}

// Step 8: Update msg object
msg.topic.filepath = outputPath;
msg.topic.name = outputName;
msg.topic.extension = "txt";
msg.topic.keywords = [...msg.topic.keywords, 'slides images', 'interpreted']
node.warn('Procesamiento de slides finalizado, todas las respuestas acumuladas han sido guardadas.');

msg.totalUsagePPTXtoSlides = msg.allUsage.reduce((totals, usage) => {
    totals.completion_tokens += usage.completion_tokens;
    totals.prompt_tokens += usage.prompt_tokens;
    totals.total_tokens += usage.total_tokens;
    return totals;
}, { completion_tokens: 0, prompt_tokens: 0, total_tokens: 0 });

const folderPath = '/internal-storage-files/files/images/';
fs.readdir(folderPath, (err, files) => {
    if (err) {
        node.warn(`Error leyendo la carpeta: ${err}`);
        return;
    }

    for (const file of files) {
        const filePath = path.join(folderPath, file);
        fs.unlink(filePath, (err) => {
            if (err) {
                node.warn(`Error borrando el archivo ${filePath}: ${err}`);
            }
        });
    }
});



return msg;

